import React from "react";
import { NavLink } from "react-router-dom";
import "./NavLinks.css";

const NavLinks = () => {
  return (
    <ul className="nav-links">
      <li>
        <NavLink to="/" exact="true">
          ALL USERS
        </NavLink>
      </li>

      <li>
        <NavLink to="/u1/places">
          MY PLACES
        </NavLink>
      </li>

      <li>
        <NavLink to="/places/new">
          ADD PLACE
        </NavLink>
      </li>

      <li>
        <button>AUTHENTICATE</button>
      </li>
    </ul>
  );
};

export default NavLinks;
